CREATE TABLE IF NOT EXISTS media_assets (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL, asset_key TEXT NOT NULL, asset_type TEXT NOT NULL, cdn_url TEXT NOT NULL, alt_text TEXT, caption_text TEXT, is_public BOOLEAN DEFAULT FALSE, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS learning_resources (id TEXT PRIMARY KEY, tenant_id UUID NOT NULL, section TEXT NOT NULL, course TEXT NOT NULL, level TEXT NOT NULL, module TEXT NOT NULL, resource_type TEXT NOT NULL, title TEXT NOT NULL, docx_url TEXT, pdf_url TEXT, html_url TEXT, adaptive_use TEXT, requires_paid_access BOOLEAN DEFAULT TRUE, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS video_lessons (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL, course_code TEXT NOT NULL, module_code TEXT NOT NULL, provider TEXT NOT NULL DEFAULT 'HeyGen', hosting_provider TEXT, heygen_project_url TEXT, video_url TEXT NOT NULL, embed_url TEXT, caption_vtt_url TEXT, thumbnail_url TEXT, transcript_url TEXT, completion_rule JSONB NOT NULL, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS learner_video_progress (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL, learner_id UUID NOT NULL, module_code TEXT NOT NULL, video_lesson_id UUID REFERENCES video_lessons(id), progress_ratio NUMERIC(5,4) DEFAULT 0, completed BOOLEAN DEFAULT FALSE, last_position_seconds INTEGER DEFAULT 0, updated_at TIMESTAMPTZ DEFAULT now(), UNIQUE(tenant_id, learner_id, module_code, video_lesson_id));
